Material.Shader:
varying vec3 N;
varying vec3 V;
varying vec3 L;

void main(void)
{   
    // adjust normals to eye direction
    vec3 normalCorrected = gl_Normal;
    V = normalize(gl_ModelViewMatrixInverse * vec4(0.0, 0.0, 0.0, 1.0)).xyz;

    float dotnormal = dot(gl_Normal, V);
    if(0.0 > dotnormal)
	normalCorrected = vec3(0.0 - normalCorrected.x, 0.0 - normalCorrected.y, 0.0 - normalCorrected.z);

    N = normalize(gl_NormalMatrix*normalCorrected);
    V = -vec3(gl_ModelViewMatrix*gl_Vertex);
	L = vec3(gl_ModelViewMatrix*(vec4(gl_LightSource[0].position)-gl_Vertex));
    gl_Position = ftransform();
}

varying vec3 N;
varying vec3 V;
varying vec3 L;

void main()
{ 
	float w = 0.18*(1.0);

    vec3 l = normalize(L);
    vec3 n = normalize(N);
    vec3 v = normalize(V);
    vec3 h = normalize(l+v);

    float diffuse = abs(dot(l,n));
    float specular = smoothstep(0.72-w,0.72+w,pow(max(0.0,abs(dot(n,h))),1.0));

    gl_FragColor = vec4(gl_LightSource[0].diffuse*diffuse +gl_LightSource[0].specular*specular);
}
